import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { Button, Input, icon } from 'decantr/components';
import { link } from 'decantr/router';

code.example:
function PageTree({ pages, favorites, currentPageId, onReorder, onRename, onDelete, onNewPage }) {
  const { div, span, input, nav, ul, li, button } = tags;
  const [searchQuery, setSearchQuery] = createSignal('');
  const [expandedIds, setExpandedIds] = createSignal(new Set());
  const [editingId, setEditingId] = createSignal(null);
  const [contextMenu, setContextMenu] = createSignal(null);

  const toggleExpand = (id) => {
    const expanded = new Set(expandedIds());
    expanded.has(id) ? expanded.delete(id) : expanded.add(id);
    setExpandedIds(expanded);
  };

  const filterPages = (pages, query) => {
    if (!query) return pages;
    return pages.filter(p => 
      p.title.toLowerCase().includes(query.toLowerCase()) ||
      (p.children && filterPages(p.children, query).length > 0)
    );
  };

  const renderPage = (page, depth = 0) => {
    const isActive = page.id === currentPageId;
    const isExpanded = expandedIds().has(page.id);
    const hasChildren = page.children && page.children.length > 0;
    const isEditing = editingId() === page.id;

    return li({ key: page.id, class: css('_list[none]') },
      div({
        class: css(`_flex _aic _gap1 _py1 _px2 _r1 _cursor[pointer] _trans ${isActive ? '_bg[var(--primary)/10] _fg[var(--primary)]' : '_hover:bg[var(--surface-raised)]'}`),
        style: `padding-left: ${depth * 16 + 8}px`,
        draggable: !isEditing,
        ondragstart: (e) => e.dataTransfer.setData('pageId', page.id),
        ondragover: (e) => e.preventDefault(),
        ondrop: (e) => onReorder(e.dataTransfer.getData('pageId'), page.id),
        oncontextmenu: (e) => { e.preventDefault(); setContextMenu({ id: page.id, x: e.clientX, y: e.clientY }); }
      },
        // Expand toggle
        hasChildren ? button({
          class: css('_p0.5 _r1 _hover:bg[var(--surface)]'),
          onclick: (e) => { e.stopPropagation(); toggleExpand(page.id); }
        }, icon(isExpanded ? 'chevron-down' : 'chevron-right', { size: '12' })) 
        : span({ class: css('_w5') }),
        // Icon
        span({ class: css('_text[1.1em]') }, page.icon || '📄'),
        // Title (editable)
        isEditing ? input({
          type: 'text',
          value: page.title,
          class: css('_flex1 _px1 _py0.5 _textsm _border _r1'),
          autofocus: true,
          onblur: (e) => { onRename(page.id, e.target.value); setEditingId(null); },
          onkeydown: (e) => { if (e.key === 'Enter') e.target.blur(); if (e.key === 'Escape') setEditingId(null); },
          onclick: (e) => e.stopPropagation()
        }) : link({
          href: `/doc/${page.id}`,
          class: css('_flex1 _textsm _truncate _nounder _fgfg'),
          ondblclick: (e) => { e.preventDefault(); setEditingId(page.id); }
        }, page.title)
      ),
      // Children
      hasChildren && isExpanded ? ul({ class: css('_list[none] _m0 _p0') },
        ...page.children.map(child => renderPage(child, depth + 1))
      ) : null
    );
  };

  const filteredPages = filterPages(pages, searchQuery());

  return nav({ class: css('_flex _col _hfull') },
    // Search
    div({ class: css('_p2') },
      div({ class: css('_flex _aic _gap2 _px2 _py1.5 _r1 _border _bg[var(--surface)]') },
        icon('search', { size: '14', class: css('_fgmuted') }),
        input({
          type: 'text',
          placeholder: 'Search pages...',
          class: css('_flex1 _border[none] _outline[none] _textsm _bg[transparent]'),
          value: searchQuery(),
          onInput: (e) => setSearchQuery(e.target.value)
        })
      )
    ),
    // Favorites
    favorites.length > 0 ? div({ class: css('_px2 _pb2') },
      span({ class: css('_textxs _fgmuted _fontmedium _uppercase _tracking[0.05em]') }, 'Favorites'),
      ul({ class: css('_list[none] _m0 _p0 _mt1') },
        ...favorites.map(f => renderPage(f))
      )
    ) : null,
    // Main tree
    div({ class: css('_flex1 _overflow[auto] _px2') },
      span({ class: css('_textxs _fgmuted _fontmedium _uppercase _tracking[0.05em]') }, 'Pages'),
      ul({ class: css('_list[none] _m0 _p0 _mt1') },
        ...filteredPages.map(p => renderPage(p))
      )
    ),
    // New page button
    div({ class: css('_p2 _borderT') },
      Button({ variant: 'outline', class: css('_wfull'), onclick: onNewPage },
        icon('plus', { size: '14' }), ' New Page'
      )
    ),
    // Context menu
    contextMenu() ? div({
      class: css('_fixed _bg[var(--surface)] _shadow _r1 _border _py1 _z[100]'),
      style: `top: ${contextMenu().y}px; left: ${contextMenu().x}px`
    },
      button({ class: css('_flex _aic _gap2 _w[full] _px3 _py1.5 _textsm _hover:bg[var(--surface-raised)]'), onclick: () => { setEditingId(contextMenu().id); setContextMenu(null); } },
        icon('edit-2', { size: '14' }), 'Rename'
      ),
      button({ class: css('_flex _aic _gap2 _w[full] _px3 _py1.5 _textsm _hover:bg[var(--surface-raised)]'), onclick: () => { onDelete(contextMenu().id); setContextMenu(null); } },
        icon('trash-2', { size: '14' }), 'Delete'
      )
    ) : null
  );
}

