function CompactPageTree({ pages, currentPageId }) {
  const { nav, ul, li, span } = tags;

  const renderPage = (page, depth = 0) => li({ class: css('_list[none]') },
    link({
      href: `/doc/${page.id}`,
      class: css(`_flex _aic _gap1 _py0.5 _px2 _textxs _truncate _nounder ${page.id === currentPageId ? '_fg[var(--primary)]' : '_fgfg'}`),
      style: `padding-left: ${depth * 12 + 4}px`
    },
      span({ class: css('_text[0.9em]') }, page.icon || '📄'),
      page.title
    ),
    page.children ? ul({ class: css('_list[none] _m0 _p0') },
      ...page.children.map(c => renderPage(c, depth + 1))
    ) : null
  );

  return nav({ class: css('_flex _col') },
    ul({ class: css('_list[none] _m0 _p0') },
      ...pages.map(p => renderPage(p))
    )
  );
}

