function FlatPageList({ pages, currentPageId, onNewPage }) {
  const { nav, div, input, span } = tags;
  const [query, setQuery] = createSignal('');

  const filtered = pages.filter(p => p.title.toLowerCase().includes(query().toLowerCase()));

  return nav({ class: css('_flex _col _gap2 _p2') },
    div({ class: css('_flex _aic _gap2 _px2 _py1.5 _r1 _border') },
      icon('search', { size: '14', class: css('_fgmuted') }),
      input({
        type: 'text',
        placeholder: 'Search...',
        class: css('_flex1 _border[none] _outline[none] _textsm'),
        onInput: (e) => setQuery(e.target.value)
      })
    ),
    ...filtered.map(page =>
      link({
        href: `/doc/${page.id}`,
        class: css(`_flex _aic _gap2 _p2 _r1 _nounder ${page.id === currentPageId ? '_bg[var(--primary)/10] _fg[var(--primary)]' : '_hover:bg[var(--surface-raised)]'}`)
      },
        span({ class: css('_text[1.1em]') }, page.icon || '📄'),
        span({ class: css('_textsm _truncate') }, page.title)
      )
    ),
    Button({ variant: 'outline', onclick: onNewPage },
      icon('plus', { size: '14' }), ' New Page'
    )
  );
}

